import { zodResolver } from '@hookform/resolvers/zod';
import { useForm, useFieldArray, UseFormReturn } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Calendar } from '@/components/ui/calendar';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { CalendarIcon, Loader2, Minus, Plus, ShoppingCart, AlertCircle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { format, add } from 'date-fns';
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from '@/components/ui/card';
import {
    boxHireServices,
    services,
    protectionAddOns,
    tvProtectionAddOns,
} from '@/lib/data';
import { useState, useMemo } from 'react';
import { useToast } from '@/hooks/use-toast';
import { Service } from '@/lib/types';
import { Textarea } from '@/components/ui/textarea';
import { Separator } from './ui/separator';
import { useFirebase, useUser } from '@/firebase';
import { collection } from 'firebase/firestore';
import { addDocumentNonBlocking } from '@/firebase/non-blocking-updates';
import { useRouter } from 'next/navigation';
import { recommendAdditionalEquipment } from '@/ai/flows/recommend-additional-equipment';

const allItems = [
    ...boxHireServices,
    ...services,
    ...protectionAddOns,
    ...tvProtectionAddOns,
];

const itemSchema = z.object({
    id: z.string(),
    name: z.string(),
    quantity: z.number().min(1),
    type: z.enum(['hire', 'purchase']).optional(),
    price: z.number(),
});

const formSchema = z.object({
  projectDescription: z.string().optional(),
  items: z.array(itemSchema).refine((value) => value.length > 0, {
    message: 'You have to select at least one item.',
  }),
  rentalStartDate: z.date({
    required_error: 'A start date is required.',
  }),
  rentalEndDate: z.date({
    required_error: 'An end date is required.',
  }),
});

type QuoteFormValues = z.infer<typeof formSchema>;

function QuantitySelector({ form, itemId, itemName, type, price }: { form: UseFormReturn<QuoteFormValues>, itemId: string, itemName: string, type?: 'hire' | 'purchase', price: number }) {
    const { control, watch } = form;
    
    const { fields, append, remove, update } = useFieldArray({
        control,
        name: "items"
    });

    const uniqueId = type ? `${itemId}-${type}` : itemId;
    const items = watch('items');
    const itemIndex = items.findIndex(item => item.id === uniqueId);
    
    const currentQuantity = itemIndex !== -1 ? items[itemIndex].quantity : 0;

    const handleQuantityChange = (change: number) => {
        const newQuantity = Math.max(0, currentQuantity + change);

        if (newQuantity === 0) {
            if (itemIndex !== -1) {
                remove(itemIndex);
            }
        } else {
            if (itemIndex === -1) {
                append({ id: uniqueId, name: itemName, quantity: newQuantity, type, price });
            } else {
                update(itemIndex, { ...items[itemIndex], quantity: newQuantity });
            }
        }
    };
    
    return (
        <div className="flex items-center gap-2">
            <Button type="button" variant="outline" size="icon" className="h-8 w-8" onClick={() => handleQuantityChange(-1)}>
                <Minus className="h-4 w-4" />
            </Button>
            <Input
                readOnly
                value={currentQuantity}
                className="h-8 w-12 text-center"
            />
            <Button type="button" variant="outline" size="icon" className="h-8 w-8" onClick={() => handleQuantityChange(1)}>
                <Plus className="h-4 w-4" />
            </Button>
        </div>
    );
}

function ItemSelector({ item, form }: { item: Service, form: UseFormReturn<QuoteFormValues> }) {
    const hasHire = 'hirePrice' in item && item.hirePrice !== undefined;
    const hasPurchase = 'purchasePrice' in item && item.purchasePrice !== undefined;

    const formatPrice = (price?: number) => {
        if (price === undefined || price === null) return '';
        return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(price);
    }

    return (
        <div className="p-3 rounded-lg border bg-card text-card-foreground">
            <p className="font-medium">{item.name}</p>
            {item.description && <p className="text-sm text-muted-foreground">{item.description}</p>}
            
            {hasHire || hasPurchase ? (
                <div className="mt-2 space-y-2">
                    {hasHire && (
                        <div className="flex items-center justify-between">
                            <p>Hire ({item.isFrom && 'from '}{formatPrice(item.hirePrice)})</p>
                            <QuantitySelector form={form} itemId={item.id} itemName={`${item.name} (Hire)`} type="hire" price={item.hirePrice!} />
                        </div>
                    )}
                     {hasPurchase && (
                        <div className="flex items-center justify-between">
                            <p>Purchase ({item.isFrom && 'from '}{formatPrice(item.purchasePrice)})</p>
                            <QuantitySelector form={form} itemId={item.id} itemName={`${item.name} (Purchase)`} type="purchase" price={item.purchasePrice!} />
                        </div>
                    )}
                </div>
            ) : (
                 <div className="flex items-center justify-between mt-2">
                    <p className="font-semibold">{item.priceString ? item.priceString : formatPrice(item.price)}</p>
                    <QuantitySelector form={form} itemId={item.id} itemName={item.name} price={item.price || 0} />
                </div>
            )}
        </div>
    );
}


function ItemList({ title, items, form, subheading }: { form: UseFormReturn<QuoteFormValues>, title: string, items: Service[], subheading?: string }) {
    return (
        <div>
            {title && <h3 className="text-lg font-semibold mb-4">{title}</h3>}
            {subheading && <h4 className="text-md font-medium mb-2">{subheading}</h4>}
            <div className="space-y-2">
                {items.map((item) => (
                    <ItemSelector key={item.id} item={item} form={form} />
                ))}
            </div>
        </div>
    )
}

function QuoteSummary({ form }: { form: UseFormReturn<QuoteFormValues> }) {
    const items = form.watch('items');
    const deliveryFee = 20;
    
    const { totalItems, subtotal } = useMemo(() => {
        let totalItems = 0;
        let subtotal = 0;
        if (Array.isArray(items)) {
            totalItems = items.reduce((acc, item) => acc + item.quantity, 0);
            subtotal = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
        }
        return { totalItems, subtotal };
    }, [items]);

    const estimatedTotal = totalItems > 0 ? subtotal + deliveryFee : 0;

    return (
        <Card className="sticky top-24">
            <CardHeader className="flex flex-row items-center gap-4">
                <ShoppingCart className="h-8 w-8 text-muted-foreground" />
                <div>
                    <CardTitle>Your Quote Request</CardTitle>
                    <CardDescription>Review your items before submitting.</CardDescription>
                </div>
            </CardHeader>
            <CardContent className="max-h-96 overflow-y-auto">
                {totalItems > 0 ? (
                    <ul className="space-y-2">
                        {items.map((item, index) => (
                            <li key={`${item.id}-${index}`} className="flex justify-between items-center text-sm">
                                <span className="text-muted-foreground">{item.name}</span>
                                <span className="font-medium">Qty: {item.quantity}</span>
                            </li>
                        ))}
                    </ul>
                ) : (
                    <p className="text-sm text-muted-foreground text-center py-8">Select items from the list to add them to your quote.</p>
                )}
            </CardContent>
            {totalItems > 0 && (
                <CardFooter className="flex-col items-stretch space-y-2">
                    <Separator className="mb-2" />
                     <div className="flex justify-between w-full text-sm">
                        <span className="text-muted-foreground">Subtotal</span>
                        <span>{new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(subtotal)}</span>
                    </div>
                    <div className="flex justify-between w-full text-sm">
                        <span className="text-muted-foreground">Delivery Fee</span>
                        <span>{new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(deliveryFee)}</span>
                    </div>
                    <Separator className="my-2" />
                     <div className="flex justify-between w-full font-bold text-lg">
                        <span>Estimated Total</span>
                        <span>{new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(estimatedTotal)}</span>
                    </div>
                </CardFooter>
            )}
        </Card>
    );
}

export function QuoteForm() {
    const [isLoading, setIsLoading] = useState(false);
    const { toast } = useToast();
    const { firestore, user } = useFirebase();
    const router = useRouter();


  const form = useForm<QuoteFormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      projectDescription: '',
      items: [],
    },
  });

  async function onSubmit(values: QuoteFormValues) {
    setIsLoading(true);
    if (!user || !firestore) {
        toast({
            variant: 'destructive',
            title: 'Authentication Error',
            description: 'You must be logged in to submit a quote request.',
        });
        setIsLoading(false);
        return;
    }

    try {
        const quoteData = {
            ...values,
            rentalStartDate: values.rentalStartDate.toISOString(),
            rentalEndDate: values.rentalEndDate.toISOString(),
            customerId: user.uid,
            customerName: user.isAnonymous ? 'Anonymous User' : user.displayName,
            customerEmail: user.isAnonymous ? `anon-${user.uid}@example.com` : user.email,
            status: 'Pending',
            submittedDate: new Date().toISOString(),
        };

        const quoteRequestsRef = collection(firestore, 'customers', user.uid, 'quoteRequests');
        addDocumentNonBlocking(quoteRequestsRef, quoteData);

      // AI Recommendation
      let recommendationText = '';
      try {
        const equipmentList = values.items.map(item => item.name).join(', ');
        if (equipmentList) {
            const recommendations = await recommendAdditionalEquipment({ equipmentList });
            if (recommendations.recommendedEquipment) {
              recommendationText = `Based on your items, you might also need: ${recommendations.recommendedEquipment}.`;
            }
        }
      } catch (aiError) {
        console.error("AI recommendation failed:", aiError);
        // Don't block submission if AI fails, just log it.
      }

      toast({
        title: 'Quote Request Submitted!',
        description: `We've received your request. ${recommendationText} We'll redirect you to your requests page shortly.`,
        duration: 9000,
      });
      
      form.reset();

      // Delay redirection to allow user to read the toast
      setTimeout(() => {
        router.push('/tracking');
      }, 5000);

    } catch (error) {
      console.error('Failed to submit quote', error);
      toast({
        variant: 'destructive',
        title: 'Submission Failed',
        description: 'There was a problem submitting your quote request. Please try again.',
      });
    } finally {
        setIsLoading(false);
    }
  }

  const handleStartDateSelect = (date: Date | undefined) => {
    if (date) {
      form.setValue('rentalStartDate', date);
      const twoWeeksLater = add(date, { weeks: 2 });
      form.setValue('rentalEndDate', twoWeeksLater);
    } else {
        form.setValue('rentalStartDate', undefined as any);
        form.setValue('rentalEndDate', undefined as any);
    }
  };

  const rentalStartDate = form.watch('rentalStartDate');

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-3xl font-headline">Request a Quote</CardTitle>
        <CardDescription>
          Fill out the form below to get a personalised quote for your project.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-8">
                <div className="lg:col-span-2 space-y-8">
                    {!user ? (
                        <div className="p-4 rounded-lg border bg-yellow-50 text-yellow-800 flex items-center gap-2">
                            <AlertCircle className="h-5 w-5" />
                            <span>Please wait a moment for authentication to complete...</span>
                        </div>
                    ) : (
                      <>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <FormItem>
                              <FormLabel>Full Name</FormLabel>
                              <FormControl>
                                  <Input readOnly value={user.isAnonymous ? 'Anonymous User' : user.displayName || ''} />
                              </FormControl>
                            </FormItem>
                            <FormItem>
                              <FormLabel>Email Address</FormLabel>
                              <FormControl>
                                  <Input readOnly value={user.isAnonymous ? `anon-${user.uid}@example.com` : user.email || ''} />
                              </FormControl>
                            </FormItem>
                        </div>

                        <div>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                              <FormField
                              control={form.control}
                              name="rentalStartDate"
                              render={({ field }) => (
                                  <FormItem className="flex flex-col">
                                  <FormLabel>Rental Start Date</FormLabel>
                                  <Popover>
                                      <PopoverTrigger asChild>
                                      <FormControl>
                                          <Button
                                          variant={'outline'}
                                          className={cn(
                                              'w-full pl-3 text-left font-normal',
                                              !field.value && 'text-muted-foreground'
                                          )}
                                          >
                                          {field.value ? (
                                              format(field.value, 'PPP')
                                          ) : (
                                              <span>Pick a date</span>
                                          )}
                                          <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                          </Button>
                                      </FormControl>
                                      </PopoverTrigger>
                                      <PopoverContent className="w-auto p-0" align="start">
                                      <Calendar
                                          mode="single"
                                          selected={field.value}
                                          onSelect={handleStartDateSelect}
                                          disabled={(date) =>
                                              date < new Date(new Date().setHours(0, 0, 0, 0))
                                          }
                                          initialFocus
                                      />
                                      </PopoverContent>
                                  </Popover>
                                  <FormMessage />
                                  </FormItem>
                              )}
                              />
                              <FormField
                              control={form.control}
                              name="rentalEndDate"
                              render={({ field }) => (
                                  <FormItem className="flex flex-col">
                                  <FormLabel>Rental End Date</FormLabel>
                                  <Popover>
                                      <PopoverTrigger asChild>
                                      <FormControl>
                                          <Button
                                          variant={'outline'}
                                          className={cn(
                                              'w-full pl-3 text-left font-normal',
                                              !field.value && 'text-muted-foreground'
                                          )}
                                          >
                                          {field.value ? (
                                              format(field.value, 'PPP')
                                          ) : (
                                              <span>Pick a date</span>
                                          )}
                                          <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                          </Button>
                                      </FormControl>
                                      </PopoverTrigger>
                                      <PopoverContent className="w-auto p-0" align="start">
                                      <Calendar
                                          mode="single"
                                          selected={field.value}
                                          onSelect={field.onChange}
                                          disabled={(date) => {
                                              if (!rentalStartDate) {
                                                  return date < new Date(new Date().setHours(0, 0, 0, 0));
                                              }
                                              const twoWeeksLater = add(rentalStartDate, { weeks: 2 });
                                              return date < rentalStartDate || date > twoWeeksLater;
                                          }}
                                          initialFocus
                                      />
                                      </PopoverContent>
                                  </Popover>
                                  <FormMessage />
                                  </FormItem>
                              )}
                              />
                          </div>
                          <p className="text-sm text-muted-foreground mt-2">
                            If a longer hire period is needed, please select the maximum 2-week duration and contact us to help sort your collection date.
                          </p>
                        </div>
                        
                        <FormField
                            control={form.control}
                            name="items"
                            render={() => (
                                <FormItem>
                                    <div className="mb-4">
                                        <FormLabel className="text-base">Select Items</FormLabel>
                                        <FormDescription>
                                            Choose the items you&apos;d like to include in your quote. Adjust quantities or select hire/purchase options.
                                        </FormDescription>
                                    </div>
                                    <div className="space-y-8">
                                    <ItemList form={form} title="Box Hire" items={boxHireServices} />
                                    <ItemList form={form} title="Optional Add-Ons" items={services} />
                                        <div className="space-y-6">
                                            <h3 className="text-lg font-semibold">Protection Add-Ons</h3>
                                            <ItemList form={form} title="" subheading="Mattress Protection" items={protectionAddOns} />
                                            <ItemList form={form} title="" subheading="TV Protection" items={tvProtectionAddOns} />
                                        </div>
                                    </div>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                        control={form.control}
                        name="projectDescription"
                        render={({ field }) => (
                            <FormItem>
                            <FormLabel>Additional Information</FormLabel>
                            <FormControl>
                                <Textarea
                                placeholder="Please add any quantities and special requests here."
                                className="resize-none"
                                {...field}
                                />
                            </FormControl>
                            <FormMessage />
                            </FormItem>
                        )}
                        />

                        <Button type="submit" disabled={isLoading || !user}>
                            {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                        Submit Quote Request
                        </Button>
                      </>
                    )}
                </div>
                <div className="lg:col-span-1">
                    <QuoteSummary form={form} />
                </div>
            </div>
          </form>
        </Form>
      </CardContent>
    </Card>
  );
}
